/**
 * job-match.js — scans for jobs and matches to skills
 * 
 * runs each cycle, finds relevant opportunities,
 * posts to issues for visibility.
 * 
 * monetization: premium matching, custom alerts, API access
 */

const fs = require("fs");
const path = require("path");

const JOBS_PATH = path.resolve(__dirname, "../memory/jobs.json");

// skill profiles to match against
const PROFILES = [
  {
    id: "solidity-dev",
    name: "Solidity Developer",
    skills: ["solidity", "ethereum", "smart contracts", "defi", "foundry", "hardhat"],
    keywords: ["solidity", "smart contract", "defi", "web3", "blockchain developer"]
  },
  {
    id: "ai-engineer",
    name: "AI Engineer",
    skills: ["python", "pytorch", "tensorflow", "llm", "machine learning", "rag"],
    keywords: ["ai engineer", "machine learning", "llm", "ml engineer", "ai developer"]
  },
  {
    id: "fullstack",
    name: "Full Stack Developer",
    skills: ["javascript", "typescript", "react", "node", "python", "sql"],
    keywords: ["full stack", "fullstack", "frontend backend", "web developer"]
  }
];

// job sources (would be expanded with real APIs)
const SOURCES = [
  { name: "remoteok", url: "https://remoteok.com/api" },
  { name: "github-jobs", url: "https://jobs.github.com/positions.json" },
  { name: "web3-jobs", url: "https://web3.career/api/jobs" }
];

// mock job data for demo (in production, fetch from real APIs)
const MOCK_JOBS = [
  {
    id: "job-001",
    title: "Senior Solidity Engineer",
    company: "DeFi Protocol",
    location: "Remote",
    salary: "$150k-200k",
    url: "https://example.com/job/1",
    description: "Build smart contracts for DeFi protocol",
    posted: "2026-02-20"
  },
  {
    id: "job-002", 
    title: "AI Agent Developer",
    company: "Autonomous Labs",
    location: "Remote",
    salary: "$120k-180k",
    url: "https://example.com/job/2",
    description: "Build autonomous AI agents for crypto trading",
    posted: "2026-02-19"
  },
  {
    id: "job-003",
    title: "Full Stack Web3 Developer",
    company: "NFT Marketplace",
    location: "Remote",
    salary: "$100k-150k",
    url: "https://example.com/job/3",
    description: "React + Solidity for NFT platform",
    posted: "2026-02-18"
  }
];

function matchJob(job, profile) {
  const text = `${job.title} ${job.description}`.toLowerCase();
  const matches = profile.keywords.filter(kw => text.includes(kw.toLowerCase()));
  return {
    profile: profile.id,
    score: matches.length,
    matches: matches
  };
}

async function scanJobs() {
  console.log("scanning for jobs...");

  // in production, fetch from real APIs
  // for now, use mock data
  const jobs = MOCK_JOBS;

  // match against profiles
  const results = [];
  for (const job of jobs) {
    const matches = [];
    for (const profile of PROFILES) {
      const match = matchJob(job, profile);
      if (match.score > 0) {
        matches.push(match);
      }
    }
    if (matches.length > 0) {
      matches.sort((a, b) => b.score - a.score);
      results.push({
        job,
        bestMatch: matches[0],
        allMatches: matches
      });
    }
  }

  // sort by match score
  results.sort((a, b) => b.bestMatch.score - a.bestMatch.score);

  return results;
}

function saveResults(results) {
  const data = {
    lastScanned: new Date().toISOString(),
    totalJobs: results.length,
    matches: results
  };

  fs.mkdirSync(path.dirname(JOBS_PATH), { recursive: true });
  fs.writeFileSync(JOBS_PATH, JSON.stringify(data, null, 2));
  console.log(`saved ${results.length} matched jobs to ${JOBS_PATH}`);
}

function formatForIssue(results) {
  if (results.length === 0) {
    return "no matching jobs found this cycle.";
  }

  let md = `# job matches — ${new Date().toISOString().split("T")[0]}\n\n`;
  md += `found ${results.length} matching opportunities:\n\n`;

  for (const r of results.slice(0, 5)) { // top 5
    const { job, bestMatch } = r;
    md += `## ${job.title}\n`;
    md += `**${job.company}** · ${job.location} · ${job.salary}\n\n`;
    md += `${job.description}\n\n`;
    md += `**matched to:** ${bestMatch.profile} (${bestMatch.score} keywords)\n`;
    md += `**apply:** [${job.url}](${job.url})\n\n`;
    md += `---\n\n`;
  }

  md += `\n*scanned ${SOURCES.length} sources · updated every cycle*\n`;
  return md;
}

async function main() {
  console.log("=== JOB MATCHER ===\n");

  const results = await scanJobs();
  saveResults(results);

  console.log("\n--- MATCHED JOBS ---");
  for (const r of results.slice(0, 3)) {
    console.log(`[${r.bestMatch.score}] ${r.job.title} → ${r.bestMatch.profile}`);
  }

  console.log("\n--- ISSUE FORMAT ---");
  console.log(formatForIssue(results));
}

main().catch(console.error);
"}

